45	void ULFPHireMarketWidget::RefreshUnitList()
46	{
47		UnitButtons.Empty();
48		ButtonToUnitIndexMap.Empty();
49	
50		if (Box_UnitList)
51		{
52			Box_UnitList->ClearChildren();
53		}
54	
55		if (!CachedGameInstance || !CachedGameInstance->UnitRegistry || !Box_UnitList)
56		{
57			return;
58		}
59	
60		for (int32 i = 0; i < CachedHireMarketDefinition.UnitList.Num(); ++i)
61		{
62			const FLFPHireMarketUnitEntry& Entry = CachedHireMarketDefinition.UnitList[i];
63			FLFPUnitRegistryEntry UnitDefinition;
64			if (!CachedGameInstance->UnitRegistry->FindEntry(Entry.UnitTypeID, UnitDefinition))
65			{
66				continue;
67			}
68	
69			UButton* UnitButton = NewObject<UButton>(this);
70			if (!UnitButton)
71			{
72				continue;
73			}
74	
75			UTextBlock* Label = NewObject<UTextBlock>(UnitButton);
76			if (Label)
77			{
78				FString Suffix;
79				if (!CachedGameInstance->CanAffordGold(Entry.Price))
80				{
81					Suffix = TEXT(" [金币不足]");
82				}
83	
84				Label->SetText(FText::FromString(FString::Printf(TEXT("%s - %d%s"), *UnitDefinition.DisplayName.ToString(), Entry.Price, *Suffix)));
85				UnitButton->AddChild(Label);
86			}
87	
88			UVerticalBoxSlot* ItemSlot = Box_UnitList->AddChildToVerticalBox(UnitButton);
89			if (ItemSlot)
90			{
91				ItemSlot->SetPadding(FMargin(4.f));
92			}
93	
94			UnitButton->OnClicked.AddDynamic(this, &ULFPHireMarketWidget::OnUnitButtonClicked);
95			UnitButtons.Add(UnitButton);
96			ButtonToUnitIndexMap.Add(UnitButton, i);
97		}
