113			if (Button_Purchase) Button_Purchase->SetIsEnabled(false);
114			if (Image_SelectedUnit) Image_SelectedUnit->SetBrushFromTexture(nullptr);
115			return;
116		}
117	
118		const FLFPHireMarketUnitEntry& Entry = CachedHireMarketDefinition.UnitList[SelectedUnitIndex];
