132		{
133			Text_SelectedName->SetText(UnitDefinition.DisplayName);
134		}
135		if (Text_SelectedDescription)
136		{
137			Text_SelectedDescription->SetText(FText::FromString(BuildUnitDescription(Entry.UnitTypeID)));
138		}
139		if (Text_SelectedPrice)
140		{
141			Text_SelectedPrice->SetText(FText::FromString(FString::Printf(TEXT("价格: %d"), Entry.Price)));
142		}
143	
144		const bool bCanAfford = CachedGameInstance->CanAffordGold(Entry.Price);
145		if (Button_Purchase)
146		{
147			Button_Purchase->SetIsEnabled(bCanAfford);
148		}
