162	FString ULFPHireMarketWidget::BuildUnitDescription(FName UnitTypeID) const
163	{
164		if (!CachedGameInstance || !CachedGameInstance->UnitRegistry)
165		{
166			return TEXT("");
167		}
168	
169		FLFPUnitRegistryEntry UnitDefinition;
170		if (!CachedGameInstance->UnitRegistry->FindEntry(UnitTypeID, UnitDefinition))
171		{
172			return TEXT("单位定义缺失");
173		}
174	
175		const FString RaceName = StaticEnum<ELFPUnitRace>()->GetDisplayNameTextByValue(static_cast<int64>(UnitDefinition.Race)).ToString();
176		return FString::Printf(
177			TEXT("阶级: T%d\n种族: %s\n攻击: %d\n生命: %d\n移动: %d\n速度: %d\n行动次数: %d\n攻击次数: %d\n物理格挡: %d\n法术防御: %d\n重量: %d"),
178			UnitDefinition.Tier,
179			*RaceName,
180			UnitDefinition.BaseStats.Attack,
181			UnitDefinition.BaseStats.MaxHealth,
182			UnitDefinition.BaseStats.MaxMovement,
183			UnitDefinition.BaseStats.Speed,
184			UnitDefinition.AdvancedStats.ActionCount,
185			UnitDefinition.AdvancedStats.AttackCount,
186			UnitDefinition.AdvancedStats.PhysicalBlock,
187			UnitDefinition.AdvancedStats.MagicalDefense,
188			UnitDefinition.AdvancedStats.Weight
189		);
190	}
