319	
320		FVector2D CurrentMousePos;
321		GetMousePosition(CurrentMousePos.X, CurrentMousePos.Y);
322		FVector2D Delta = CurrentMousePos - DragStartPosition;
323	
324		CameraOffset -= FVector(-Delta.Y, Delta.X, 0) * CameraDragSpeed;
325		DragStartPosition = CurrentMousePos;
326	}
