218	void ULFPGameInstance::ApplyOwnedRelicsToUnit(ALFPTacticsUnit* Unit) const
219	{
220		if (!Unit || !RelicDataAsset)
221		{
222			return;
223		}
224	
225		for (const FName& RelicID : OwnedRelicIDs)
226		{
227			FLFPRelicDefinition Definition;
228			if (!FindRelicDefinition(RelicID, Definition))
229			{
230				continue;
231			}
232	
233			for (const FLFPRelicEffectEntry& Effect : Definition.Effects)
234			{
235				switch (Effect.EffectType)
236				{
237				case ELFPRelicEffectType::RET_MaxHealthFlat:
238					Unit->AddCurrentMaxHealth(Effect.Value);
239					break;
240				case ELFPRelicEffectType::RET_AttackFlat:
241					Unit->AddCurrentAttack(Effect.Value);
242					break;
243				case ELFPRelicEffectType::RET_DefenseFlat:
244					Unit->AddCurrentPhysicalBlock(Effect.Value);
245					break;
246				case ELFPRelicEffectType::RET_SpeedFlat:
247					Unit->AddCurrentSpeed(Effect.Value);
248					break;
249				default:
250					break;
251				}
252			}
253		}
254	}
