353	
354	TArray<FLFPUnitEntry> ULFPGameInstance::GetMergeablePairs() const
355	{
356		// 统计每个 TypeID 的出现次数
357		TMap<FName, int32> CountMap;
358	
359		for (const FLFPUnitEntry& Unit : PartyUnits)
360		{
361			if (Unit.IsValid())
362			{
363				CountMap.FindOrAdd(Unit.TypeID, 0)++;
364			}
365		}
366		for (const FLFPUnitEntry& Unit : ReserveUnits)
367		{
368			if (Unit.IsValid())
369			{
370				CountMap.FindOrAdd(Unit.TypeID, 0)++;
371			}
372		}
373	
374		// 筛选出现 >= 2 次且注册表中有进化目标的 TypeID
375		TArray<FLFPUnitEntry> Result;
376		for (const auto& Pair : CountMap)
377		{
378			if (Pair.Value >= 2 && UnitRegistry && UnitRegistry->CanEvolve(Pair.Key))
379			{
380				FLFPUnitEntry Entry;
381				Entry.TypeID = Pair.Key;
382				Entry.Tier = UnitRegistry->GetUnitTier(Pair.Key);
383				Result.Add(Entry);
384			}
385		}
386	
387		return Result;
388	}
