472	void ALFPWorldMapPlayerController::EnterBattle(ALFPWorldMapNode* BattleNode)
473	{
474		if (!BattleNode) return;
475	
476		ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
477		if (!GI) return;
478	
479		ALFPWorldMapManager* Manager = GetWorldMapManager();
480		if (!Manager) return;
481	
482		// 保存世界地图快照
483		FLFPWorldMapSnapshot Snapshot;
484		Snapshot.WorldMapName = Manager->GetCurrentWorldMapName();
485		if (ULFPWorldMapPlayerState* PS = Manager->GetPlayerState())
486		{
487			Snapshot.CurrentNodeID = PS->CurrentNodeID;
488			Snapshot.CurrentTurn = PS->CurrentTurn;
489			Snapshot.VisitedNodeIDs = PS->VisitedNodeIDs;
490			Snapshot.RevealedNodeIDs = PS->RevealedNodeIDs;
491		}
492	
493		// 收集已触发节点
494		for (const auto& Pair : Manager->GetNodeMap())
495		{
496			if (Pair.Value && Pair.Value->bHasBeenTriggered)
497			{
498				Snapshot.TriggeredNodeIDs.Add(Pair.Key);
499			}
500		}
501	
502		GI->SaveWorldMapSnapshot(Snapshot);
503	
504		// 设置战斗请求
505		FLFPBattleRequest Request;
506		Request.SourceNodeID = BattleNode->NodeID;
507		Request.BattleMapName = BattleNode->BattleMapName;
508		Request.StarRating = BattleNode->StarRating;
509		Request.bCanEscape = BattleNode->bCanEscape;
510		Request.BaseGoldReward = BattleNode->BaseGoldReward;
511		Request.BaseFoodReward = BattleNode->BaseFoodReward;
512		GI->SetBattleRequest(Request);
513	
514		// 切换到战斗关卡
515		GI->TransitionToBattle(TEXT(""));
516	}
