662	bool ALFPWorldMapManager::MovePlayer(int32 TargetNodeID)
663	{
664		if (!PlayerState) return false;
665	
666		// 棋子移动中不允许再次移动
667		if (PlayerPawn && PlayerPawn->IsMoving()) return false;
668	
669		bool bMoved = PlayerState->MoveToNode(TargetNodeID, this);
670	
671		if (bMoved)
672		{
673			ALFPWorldMapNode* TargetNode = GetNode(TargetNodeID);
674			if (!TargetNode) return true;
675	
676			// 如果有棋子，启动移动动画，延迟迷雾更新和事件触发
677			if (PlayerPawn)
678			{
679				PendingMoveTargetNodeID = TargetNodeID;
680				FVector TargetLocation = TargetNode->GetActorLocation() + FVector(0, 0, 1);
681				PlayerPawn->MoveToLocation(TargetLocation);
682			}
683			else
684			{
685				// 没有棋子，直接执行后续逻辑
686				HandlePostMove(TargetNodeID);
687			}
688		}
689	
690		return bMoved;
691	}
