720	void ALFPWorldMapPlayerController::OpenTown(ALFPWorldMapNode* TownNode)
721	{
722		if (!TownNode || !TownWidgetClass) return;
723	
724		// 解析建筑列表
725		TArray<ELFPTownBuildingType> BuildingTypes = LFPTownUtils::ParseBuildingList(TownNode->TownBuildingList);
726	
727		if (BuildingTypes.Num() == 0)
728		{
729			UE_LOG(LogTemp, Warning, TEXT("城镇节点 %d: 建筑列表为空"), TownNode->NodeID);
730			return;
731		}
732	
733		// 创建或显示 TownWidget
734		if (!TownWidget)
735		{
736			TownWidget = CreateWidget<ULFPTownWidget>(this, TownWidgetClass);
737			if (TownWidget)
738			{
739				TownWidget->OnClosed.AddDynamic(this, &ALFPWorldMapPlayerController::OnTownWidgetClosed);
740				TownWidget->OnBuildingRequested.AddDynamic(this, &ALFPWorldMapPlayerController::OnTownBuildingRequested);
741				TownWidget->AddToViewport();
742			}
743		}
744		else
745		{
746			TownWidget->SetVisibility(ESlateVisibility::Visible);
747			TownWidget->AddToViewport();
748		}
749	
750		if (TownWidget)
751		{
752			TownWidget->Setup(BuildingTypes);
753		}
754	
755		UE_LOG(LogTemp, Log, TEXT("城镇节点 %d: 打开城镇面板，建筑数量 %d"), TownNode->NodeID, BuildingTypes.Num());
756	}
