763	void ALFPWorldMapPlayerController::OnTownBuildingRequested(ELFPTownBuildingType BuildingType)
764	{
765		UE_LOG(LogTemp, Log, TEXT("城镇: 请求打开建筑 %s"), *LFPTownUtils::BuildingTypeToString(BuildingType));
766	
767		switch (BuildingType)
768		{
769		case ELFPTownBuildingType::TBT_EvolutionTower:
770			// 隐藏城镇面板，打开升华塔
771			if (TownWidget)
772			{
773				TownWidget->SetVisibility(ESlateVisibility::Hidden);
774			}
775			OpenEvolutionTower();
776			break;
777	
778		case ELFPTownBuildingType::TBT_Shop:
779			if (TownWidget)
780			{
781				TownWidget->SetVisibility(ESlateVisibility::Hidden);
782			}
783			if (SelectedNode && SelectedNode->NodeType == ELFPWorldNodeType::WNT_Town)
784			{
785				OpenShop(SelectedNode, true);
786			}
787			break;
788	
789		case ELFPTownBuildingType::TBT_Teleport:
790			// TODO: 打开传送阵 UI
791			UE_LOG(LogTemp, Log, TEXT("城镇: 传送阵功能尚未实现"));
792			break;
793	
794		case ELFPTownBuildingType::TBT_QuestNPC:
795			// TODO: 打开任务对话
796			UE_LOG(LogTemp, Log, TEXT("城镇: 任务NPC功能尚未实现"));
797			break;
798	
799		case ELFPTownBuildingType::TBT_SkillNode:
800			// TODO: 打开技能树 UI
801			UE_LOG(LogTemp, Log, TEXT("城镇: 技能节点功能尚未实现"));
802			break;
803	
804		default:
805			break;
806		}
